sp_widget.client_script:
api.controller = function ($scope, $timeout) {
  var c = this;

  var lineChart;
  var donutChart;
  var barChart;
  var instanceDistributionChart;
  var statusTrendChart;

  /* ================= INIT ================= */

  c.$onInit = function () {
    c.statusFilter   = 'all';
    c.instanceFilter = 'all';
    c.dateFilter     = 'all';
    c.tableSearch    = '';       // NEW: table name search

    c.pageSize       = 5;
    c.currentPage    = 1;
    c.totalPages     = 1;
    c.paginatedTables  = [];
    c.tablePerformance = [];

    $timeout(function () {
      if (!window.Chart) {
        console.error('ChartJS not loaded');
        return;
      }
      c.refreshDashboard();
    }, 900);
  };

  c.refreshDashboard = function () {
    buildCharts();
    c.getTablePerformance();
    c.updatePagination();
  };

  /* ================= ACTIVE FILTER COUNT ================= */

  c.activeFilterCount = function () {
    var count = 0;
    if (c.dateFilter     !== 'all') count++;
    if (c.statusFilter   !== 'all') count++;
    if (c.instanceFilter !== 'all') count++;
    if (c.tableSearch && c.tableSearch.trim()) count++;
    return count;
  };

  /* ================= CLEAR ALL FILTERS ================= */

  c.clearFilters = function () {
    c.dateFilter     = 'all';
    c.statusFilter   = 'all';
    c.instanceFilter = 'all';
    c.tableSearch    = '';
  };

  /* ================= FILTERED RUNS ================= */

  c.filteredRuns = function () {
    var runs = c.data.runs || [];

    return runs.filter(function (run) {

      /* STATUS FILTER */
      if (c.statusFilter !== 'all' && run.status !== c.statusFilter)
        return false;

      /* INSTANCE FILTER — both sides already normalized on server */
      if (c.instanceFilter !== 'all') {
        var runURL    = String(run.instance    || '').trim().replace(/\/$/, '').toLowerCase();
        var filterURL = String(c.instanceFilter || '').trim().replace(/\/$/, '').toLowerCase();
        if (runURL !== filterURL) return false;
      }

      /* TABLE SEARCH FILTER */
      if (c.tableSearch && c.tableSearch.trim()) {
        var needle   = c.tableSearch.trim().toLowerCase();
        var haystack = (run.tables || []).join(' ').toLowerCase();
        if (haystack.indexOf(needle) === -1) return false;
      }

      /* DATE FILTER — use created_raw (ISO) for reliable cross-browser parsing */
      if (c.dateFilter !== 'all') {
        var rawStr = run.created_raw || run.created || '';

        /* Normalize: replace space separator with T so Safari/Firefox parse correctly */
        var isoStr  = rawStr.replace(' ', 'T');
        var created = new Date(isoStr);

        /* If date can't be parsed, include the record rather than silently dropping it */
        if (isNaN(created.getTime())) return true;

        var now = new Date();

        if (c.dateFilter === 'today') {
          var dayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
          var dayEnd   = new Date(dayStart.getTime() + 86400000);
          if (created < dayStart || created >= dayEnd) return false;
        }

        if (c.dateFilter === 'last7') {
          var cutoff7 = new Date(now.getTime() - 7 * 86400000);
          if (created < cutoff7) return false;
        }

        if (c.dateFilter === 'lastMonth') {
          var cutoffMonth = new Date(now.getTime() - 30 * 86400000);
          if (created < cutoffMonth) return false;
        }
      }

      return true;
    });
  };

  /* ================= FILTERED KPI STATS ================= */

  c.filteredStats = function () {
    var runs = c.filteredRuns();

    var totalRuns           = runs.length;
    var successRuns         = 0;
    var failedRuns          = 0;
    var totalRecords        = 0;
    var totalDurationSeconds = 0;

    runs.forEach(function (run) {
      if (run.status === 'success') successRuns++;
      if (run.status === 'failed')  failedRuns++;

      totalRecords += parseInt(run.records || 0, 10);

      if (run.duration) {
        var match = run.duration.match(/(\d+)\s*min\s*(\d+)\s*sec/i);
        if (match) {
          totalDurationSeconds +=
            (parseInt(match[1], 10) * 60) + parseInt(match[2], 10);
        }
      }
    });

    var avgSeconds       = totalRuns ? Math.round(totalDurationSeconds / totalRuns) : 0;
    var avgMinutes       = Math.floor(avgSeconds / 60);
    var remainingSeconds = avgSeconds % 60;

    return {
      total:        totalRuns,
      success:      successRuns,
      failed:       failedRuns,
      records:      totalRecords,
      avg_duration: avgMinutes + ' min ' + remainingSeconds + ' sec',
      avg_seconds:  avgSeconds   // raw seconds used by kpiTrend
    };
  };

  /* ================= CSV EXPORT ================= */

  c.exportCSV = function () {
    var runs = c.filteredRuns();
    var csv  = [];

    csv.push(['Run ID', 'Tables', 'Records', 'Status', 'Duration', 'Created'].join(','));

    runs.forEach(function (run) {
      csv.push([
        run.number   || run.run_id || '',
        (run.tables  || []).join(' | '),
        run.records  || 0,
        run.status   || '',
        run.duration || '',
        run.created  || ''
      ].join(','));
    });

    var blob = new Blob([csv.join('\n')], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'migration-report.csv';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  /* ================= PDF EXPORT ================= */

  c.exportPDF = function () {
    var wrapper  = document.querySelector('.ra-wrapper');
    var canvases = wrapper.querySelectorAll('canvas');
    var replacements = [];

    canvases.forEach(function (cv) {
      var img    = document.createElement('img');
      img.src    = cv.toDataURL('image/png');
      img.style.width  = '100%';
      img.style.height = '295.5px';

      replacements.push({ canvas: cv, img: img });

      cv.parentNode.insertBefore(img, cv);
      cv.style.display = 'none';
    });

    requestAnimationFrame(function () {
      html2pdf()
        .set({
          margin:     15,
          filename:   'migration-report.pdf',
          image:      { type: 'jpeg', quality: 1 },
          html2canvas: { scale: 9, useCORS: true },
          jsPDF:      { unit: 'mm', format: 'a4', orientation: 'portrait' }
        })
        .from(wrapper)
        .save()
        .then(function () {
          replacements.forEach(function (r) {
            r.canvas.style.display = 'block';
            if (r.img && r.img.parentNode) {
              r.img.parentNode.removeChild(r.img);
            }
          });
        });
    });
  };

  /* ================= BUILD CHARTS ================= */

  function buildCharts() {
    var runs = c.filteredRuns();

    if (lineChart)                 lineChart.destroy();
    if (donutChart)                donutChart.destroy();
    if (barChart)                  barChart.destroy();
    if (instanceDistributionChart) instanceDistributionChart.destroy();
    if (statusTrendChart)          statusTrendChart.destroy();

    var primary = '#1F8C95';
    var success = '#1F8C95';
    var danger  = '#ef4444';
    var partial = '#FFFF00';

    if (!runs.length) {
      renderEmptyCharts(primary, success, danger);
      return;
    }

    /* ================= LINE CHART DATA ================= */

    var recordsByDate  = {};
    var successByDate  = {};

    runs.forEach(function (run) {
      if (!run.created) return;

      var safeDate = String(run.created_raw || run.created).substring(0, 10).replace(/\//g, '-');

      recordsByDate[safeDate] = (recordsByDate[safeDate] || 0) + Number(run.records || 0);

      if (run.status === 'success') {
        successByDate[safeDate] = (successByDate[safeDate] || 0) + Number(run.records || 0);
      }
    });

    var dates = Object.keys(recordsByDate).sort();

    if (!dates.length) {
      renderEmptyCharts(primary, success, danger);
      return;
    }

    var startDate = new Date(dates[0]);
    var endDate   = new Date(dates[dates.length - 1]);

    var labels        = [];
    var recordValues  = [];
    var successValues = [];

    var current = new Date(startDate);
    while (current <= endDate) {
      var isoDate =
        current.getFullYear() + '-' +
        String(current.getMonth() + 1).padStart(2, '0') + '-' +
        String(current.getDate()).padStart(2, '0');

      var displayLabel =
        current.toLocaleString('default', { month: 'short' }) + ' ' + current.getDate();

      labels.push(displayLabel);
      recordValues.push(recordsByDate[isoDate] || 0);
      successValues.push(successByDate[isoDate] || 0);

      current.setDate(current.getDate() + 1);
    }

    var ctxLine = document.getElementById('recordsLineChart').getContext('2d');
    lineChart = new Chart(ctxLine, {
      type: 'line',
      data: {
        labels: labels,
        datasets: [
          {
            label: 'records',
            data:  recordValues,
            borderColor:     '#1F8C95',
            backgroundColor: 'rgba(31,140,149,0.18)',
            borderWidth: 3,
            fill:        true,
            tension:     0.45,
            pointRadius: 4
          },
          {
            label: 'successful',
            data:  successValues,
            borderColor:     '#22c55e',
            backgroundColor: 'rgba(34,197,94,0.12)',
            borderWidth: 3,
            fill:        false,
            tension:     0.45,
            pointRadius: 4
          }
        ]
      },
      options: {
        responsive:          true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: true, position: 'bottom', labels: { usePointStyle: true } }
        },
        scales: {
          y: { beginAtZero: true, ticks: { precision: 0 }, grid: { color: '#e5e7eb' } },
          x: { grid: { display: false } }
        },
        animation: { duration: 1600 }
      }
    });

    /* ================= SUCCESS DISTRIBUTION DONUT — FIX: use run.status consistently ================= */

    var successRuns = 0;
    var partialRuns = 0;
    var failedRuns  = 0;

    runs.forEach(function (r) {
      if (r.status === 'success') successRuns++;
      else if (r.status === 'partial') partialRuns++;
      else if (r.status === 'failed')  failedRuns++;
    });

    donutChart = new Chart(document.getElementById('successDonutChart'), {
      type: 'doughnut',
      data: {
        labels: ['Success', 'Partial', 'Failed'],
        datasets: [{
          data:            [successRuns, partialRuns, failedRuns],
          backgroundColor: [success, '#f59e0b', danger],
          borderWidth:     0
        }]
      },
      options: {
        responsive:          true,
        maintainAspectRatio: false,
        cutout: '68%',
        plugins: {
          legend: {
            display:  true,
            position: 'bottom',
            labels:   { usePointStyle: true, padding: 18 }
          },
          tooltip: {
            callbacks: {
              label: function (context) {
                var total   = successRuns + partialRuns + failedRuns;
                var value   = context.raw || 0;
                var percent = total ? ((value / total) * 100).toFixed(1) : 0;
                return context.label + ': ' + value + ' runs (' + percent + '%)';
              }
            }
          }
        },
        animation: { duration: 1600, easing: 'easeOutQuart' }
      }
    });

    /* ================= INSTANCE DISTRIBUTION ================= */

    var connectionCounts = {};

    (c.data.connections || []).forEach(function (conn) {
      if (!connectionCounts[conn.name]) connectionCounts[conn.name] = 0;
      connectionCounts[conn.name]++;
    });

    var instanceLabels = Object.keys(connectionCounts);
    var instanceValues = Object.values(connectionCounts);

    if (!instanceLabels.length) {
      instanceLabels = ['No Data'];
      instanceValues = [1];
    }

    instanceDistributionChart = new Chart(
      document.getElementById('instanceDistributionChart'),
      {
        type: 'pie',
        data: {
          labels: instanceLabels,
          datasets: [{
            data:            instanceValues,
            backgroundColor: ['#1F7A84','#2A9DAF','#2A8DAF','#94A6A8','#6B8E23','#E67E22','#9B59B6'],
            borderColor:     '#ffffff',
            borderWidth:     2,
            hoverOffset:     10
          }]
        },
        options: {
          responsive:          true,
          maintainAspectRatio: false,
          plugins: { legend: { display: false } },
          animation: { duration: 1600 }
        }
      }
    );

    /* ================= MIGRATIONS ACROSS TABLES OVER TIME ================= */

    var recordsByDateAndTable = {};
    var allDates  = {};
    var allTables = {};

    runs.forEach(function (run) {
      if (!run.created) return;

      var dateKey = String(run.created_raw || run.created).substring(0, 10).replace(/\//g, '-');

      allDates[dateKey] = true;

      (run.tables || []).forEach(function (tbl) {
        allTables[tbl] = true;

        if (!recordsByDateAndTable[tbl])
          recordsByDateAndTable[tbl] = {};

        recordsByDateAndTable[tbl][dateKey] =
          (recordsByDateAndTable[tbl][dateKey] || 0) + Number(run.records || 0);
      });
    });

    var sortedDates   = Object.keys(allDates).sort();
    var displayLabels = sortedDates.map(function (d) {
      var dt = new Date(d);
      return dt.toLocaleString('default', { month: 'short' }) + ' ' + dt.getDate();
    });

    var lineShadowPlugin = {
      id: 'lineShadow',
      beforeDatasetDraw: function (chart) {
        var ctx = chart.ctx;
        ctx.save();
        ctx.shadowColor   = 'rgba(0,0,0,0.25)';
        ctx.shadowBlur    = 10;
        ctx.shadowOffsetX = 0;
        ctx.shadowOffsetY = 4;
      },
      afterDatasetDraw: function (chart) {
        chart.ctx.restore();
      }
    };

    var datasets = [];

    Object.keys(allTables).forEach(function (tbl, index) {
      var values = sortedDates.map(function (d) {
        return (recordsByDateAndTable[tbl] && recordsByDateAndTable[tbl][d]) || 0;
      });

      var hue = (index * 60) % 360;

      datasets.push({
        label:           tbl,
        data:            values,
        borderColor:     'hsl(' + hue + ',65%,45%)',
        backgroundColor: 'hsla(' + hue + ',65%,45%,0.12)',
        fill:            true,
        tension:         0.4,
        pointRadius:     4,
        pointHoverRadius:7,
        borderWidth:     3
      });
    });

    var ctxTrend = document.getElementById('statusTrendChart').getContext('2d');

    statusTrendChart = new Chart(ctxTrend, {
      type: 'line',
      data: { labels: displayLabels, datasets: datasets },
      plugins: [lineShadowPlugin],
      options: {
        responsive:          true,
        maintainAspectRatio: false,
        interaction:         { mode: 'nearest', intersect: false },
        animation:           { duration: 1800, easing: 'easeOutQuart' },
        plugins: {
          legend:  { position: 'top', labels: { usePointStyle: true, padding: 18 } },
          tooltip: { mode: 'index', intersect: false }
        },
        elements: {
          line:  { borderWidth: 3 },
          point: { radius: 4, hoverRadius: 7 }
        },
        scales: {
          y: { beginAtZero: true, grid: { color: '#e5e7eb' } },
          x: { grid: { display: false } }
        }
      }
    });

    /* ================= TOP 5 MIGRATED TABLES ================= */

    var tableCounts = {};

    runs.forEach(function (r) {
      (r.tables || []).forEach(function (tbl) {
        if (!tableCounts[tbl]) tableCounts[tbl] = 0;
        tableCounts[tbl] += Number(r.records || 0);
      });
    });

    var sortedTables = Object.keys(tableCounts).sort(function (a, b) {
      return tableCounts[b] - tableCounts[a];
    });

    var top5Tables  = sortedTables.slice(0, 5);
    var barLabels   = top5Tables;
    var barValues   = top5Tables.map(function (tbl) { return tableCounts[tbl]; });

    barChart = new Chart(document.getElementById('tablesBarChart'), {
      type: 'bar',
      data: {
        labels:   barLabels,
        datasets: [{ data: barValues, backgroundColor: primary, borderRadius: 10 }]
      },
      options: {
        indexAxis:           'y',
        responsive:          true,
        maintainAspectRatio: false,
        plugins: { legend: { display: false } },
        animation: { duration: 1600 }
      }
    });
  }

  /* ================= EMPTY CHARTS ================= */

  function renderEmptyCharts(primary, success, danger) {
    var ctxLine = document.getElementById('recordsLineChart').getContext('2d');
    lineChart = new Chart(ctxLine, {
      type: 'line',
      data: {
        labels:   ['No Data'],
        datasets: [{ label: 'records', data: [0], borderColor: primary, backgroundColor: 'rgba(31,140,149,0.18)', fill: true, tension: 0.4, pointRadius: 4 }]
      },
      options: { responsive: true, maintainAspectRatio: false }
    });

    donutChart = new Chart(document.getElementById('successDonutChart'), {
      type: 'doughnut',
      data: {
        labels:   ['Success', 'Failed'],
        datasets: [{ data: [0, 0], backgroundColor: [success, danger] }]
      },
      options: { responsive: true, maintainAspectRatio: false, cutout: '68%' }
    });

    instanceDistributionChart = new Chart(document.getElementById('instanceDistributionChart'), {
      type: 'pie',
      data: {
        labels:   ['No Data'],
        datasets: [{ data: [1], backgroundColor: ['#94A6A8'] }]
      },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }
    });

    var ctxTrend = document.getElementById('statusTrendChart').getContext('2d');
    statusTrendChart = new Chart(ctxTrend, {
      type: 'line',
      data: {
        labels:   ['Week 1', 'Week 2', 'Week 3', 'Week 4'],
        datasets: [
          { label: 'Success', data: [0,0,0,0], borderColor: success, fill: true },
          { label: 'Failed',  data: [0,0,0,0], borderColor: danger,  fill: true }
        ]
      },
      options: { responsive: true, maintainAspectRatio: false }
    });

    barChart = new Chart(document.getElementById('tablesBarChart'), {
      type: 'bar',
      data: {
        labels:   ['No Data'],
        datasets: [{ data: [0], backgroundColor: primary, borderRadius: 10 }]
      },
      options: { indexAxis: 'y', responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }
    });
  }

  /* ================= TABLE PERFORMANCE ================= */

  c.getTablePerformance = function () {
    var runs       = c.filteredRuns();
    var tableStats = {};

    runs.forEach(function (run) {
      (run.tables || []).forEach(function (tbl) {
        if (!tableStats[tbl]) {
          tableStats[tbl] = {
            name:          tbl,
            records:       0,
            runs:          0,
            durationTotal: 0,
            successRuns:   0,
            failedRuns:    0
          };
        }

        tableStats[tbl].records += parseInt(run.records || 0, 10);
        tableStats[tbl].runs++;

        if (run.status === 'success') tableStats[tbl].successRuns++;
        if (run.status === 'failed')  tableStats[tbl].failedRuns++;

        var match = (run.duration || '').match(/(\d+)\s*min\s*(\d+)\s*sec/i);
        if (match) {
          tableStats[tbl].durationTotal +=
            (parseInt(match[1], 10) * 60) + parseInt(match[2], 10);
        }
      });
    });

    c.tablePerformance = Object.keys(tableStats).map(function (tbl) {
      var avgSeconds = Math.round(tableStats[tbl].durationTotal / (tableStats[tbl].runs || 1));
      var avgMin     = Math.floor(avgSeconds / 60);
      var avgSec     = avgSeconds % 60;

      var totalSeconds  = tableStats[tbl].durationTotal;
      var totalRecords  = tableStats[tbl].records;
      var recordsPerSec = totalSeconds > 0 ? totalRecords / totalSeconds : 0;

      var performance = 'Excellent';
      if      (recordsPerSec < 0.02) performance = 'Slow';
      else if (recordsPerSec < 0.2)  performance = 'Good';

      var status = 'Success';
      if (tableStats[tbl].successRuns > 0 && tableStats[tbl].failedRuns > 0) {
        status = 'Partial';
      } else if (tableStats[tbl].successRuns === 0 && tableStats[tbl].failedRuns > 0) {
        status = 'Failed';
      }

      return {
        name:         tbl,
        records:      tableStats[tbl].records,
        runs:         tableStats[tbl].runs,
        status:       status,
        avg_duration: avgMin + 'm ' + avgSec + 's',
        performance:  performance
      };
    });

    c.currentPage = 1;
    c.updatePagination();
    return c.tablePerformance;
  };

  /* ================= PAGINATION ================= */

  c.pageSize    = 5;
  c.currentPage = 1;
  c.totalPages  = 1;
  c.paginatedTables = [];

  c.updatePagination = function () {
    if (!c.tablePerformance || !c.tablePerformance.length) {
      c.paginatedTables = [];
      c.totalPages      = 1;
      return;
    }

    c.totalPages = Math.ceil(c.tablePerformance.length / c.pageSize) || 1;

    var start = (c.currentPage - 1) * c.pageSize;
    var end   = start + c.pageSize;

    c.paginatedTables = c.tablePerformance.slice(start, end);
  };

  c.nextPage = function () {
    if (c.currentPage < c.totalPages) {
      c.currentPage++;
      c.updatePagination();
    }
  };

  c.prevPage = function () {
    if (c.currentPage > 1) {
      c.currentPage--;
      c.updatePagination();
    }
  };

 /* ================= KPI TREND ================= */

c.kpiTrend = function (metric) {

  var runs    = c.filteredRuns();
  var allRuns = c.data.runs || [];

  if (!runs.length) return { direction: 'up', color: 'green', value: 0 };

  /* All Time has no previous period to compare — return neutral zero */
  if (c.dateFilter === 'all') {
    return { direction: 'up', color: 'green', value: 0 };
  }

  var today    = new Date();
  var prevRuns = [];

  if (c.dateFilter === 'today') {
    var yday    = new Date(today);
    yday.setDate(today.getDate() - 1);
    var ydayStr = yday.toDateString();

    prevRuns = allRuns.filter(function (r) {
      var rawStr = (r.created_raw || r.created || '').replace(' ', 'T');
      var d      = new Date(rawStr);
      return !isNaN(d.getTime()) && d.toDateString() === ydayStr;
    });
  }

  else if (c.dateFilter === 'last7') {
    var last14 = new Date(today.getTime() - 14 * 86400000);
    var last7  = new Date(today.getTime() - 7  * 86400000);

    prevRuns = allRuns.filter(function (r) {
      var rawStr = (r.created_raw || r.created || '').replace(' ', 'T');
      var d      = new Date(rawStr);
      return !isNaN(d.getTime()) && d >= last14 && d < last7;
    });
  }

  else if (c.dateFilter === 'lastMonth') {
    var prevMonthStart = new Date(today.getFullYear(), today.getMonth() - 2, 1);
    var prevMonthEnd   = new Date(today.getFullYear(), today.getMonth() - 1, 1);

    prevRuns = allRuns.filter(function (r) {
      var rawStr = (r.created_raw || r.created || '').replace(' ', 'T');
      var d      = new Date(rawStr);
      return !isNaN(d.getTime()) && d >= prevMonthStart && d < prevMonthEnd;
    });
  }

  /* ---- Previous period stats ---- */

  var prevDurationTotal = prevRuns.reduce(function (sum, r) {
    var match = (r.duration || '').match(/(\d+)\s*min\s*(\d+)\s*sec/i);
    if (match) return sum + (parseInt(match[1], 10) * 60) + parseInt(match[2], 10);
    return sum;
  }, 0);

  var prevStats = {
    total:      prevRuns.length,
    success:    prevRuns.filter(function (r) { return r.status === 'success'; }).length,
    avgSeconds: prevRuns.length ? Math.round(prevDurationTotal / prevRuns.length) : 0
  };

  var currentStats = c.filteredStats();

  var currentValue = 0;
  var prevValue    = 0;

  if (metric === 'runs') {
    currentValue = currentStats.total;
    prevValue    = prevStats.total;
  }

  else if (metric === 'success') {
    currentValue = currentStats.success;
    prevValue    = prevStats.success;
  }

  else if (metric === 'duration') {
    /* FIX: use raw seconds not formatted string */
    currentValue = currentStats.avg_seconds || 0;
    prevValue    = prevStats.avgSeconds;
  }

  var delta    = currentValue - prevValue;
  var improved = metric === 'duration' ? delta < 0 : delta > 0;

  return {
    direction: improved ? 'up' : 'down',
    color:     improved ? 'green' : 'red',
    value:     Math.abs(delta)
  };

};

  /* ================= FILTER WATCH — FIX: 50ms delay so digest completes before rebuild ================= */

  $scope.$watch(
    function () {
      return [c.statusFilter, c.instanceFilter, c.dateFilter, c.tableSearch];
    },
    function (newVal, oldVal) {
      if (!newVal || angular.equals(newVal, oldVal)) return;
      $timeout(function () {
        c.refreshDashboard();
      }, 50);
    },
    true
  );
};

sp_widget.css:
/* ================= PRINT ================= */

@media print {

.ra-sidebar,
.dm-sidebar-slot,
.ra-actions,
.ra-filter{
    display:none !important;
}


.ra-chart-card{
    page-break-inside: avoid !important;
}

#successDonutChart{
    page-break-before: always;
}

}

/* ================= GLOBAL ================= */



/* ================= PAGE LAYOUT ================= */

.dm-page-layout{
    display:flex;
    width:100%;
    max-height:calc(100vh - 64px);
    background:linear-gradient(180deg,#f3f7ff,#eef4ff);
}
.ra-wrapper{
  width:100% !important;
  padding:20px;
  position:relative;
  overflow-y:auto;
  max-height:calc(100vh - 64px);
  flex:1;
}

.dm-sidebar-slot{
    width:260px;
}





/* ================= MAIN WRAPPER ================= */


/* ================= HEADER ================= */

.ra-header{
    display:flex;
    justify-content:space-between;
    align-items:center;
    margin-bottom:30px;
}

.ra-header h1{
    font-size:34px;
    font-weight:700;
    color:#1e293b;
}

.ra-header p{
    margin-top:4px;
    color:#64748b;
}

/* ================= BUTTONS ================= */

.ra-actions{
    display:flex;
    gap:16px;
}

.btn{
    border-radius:10px;
    padding:10px 18px;
    border:none;
    font-weight:600;
    cursor:pointer;
    transition:.2s ease;

    display:inline-flex;          /* FIX alignment */
    align-items:center;           /* center icon + text */
    gap:8px;                      /* space between icon & text */
}

/* fix svg size */
.btn svg{
    width:18px;
    height:18px;
}

/* CSV button (match screenshot look) */
.btn.secondary{
    background:#f8fafc;           /* lighter */
    border:1px solid #e5e7eb;     /* subtle border */
    color:#111827;
}

/* PDF button */
.btn.primary{
    background:#1F8C95;
    color:#fff;
    box-shadow:0 4px 10px rgba(31,140,149,.25);
}

.btn.primary:hover{
    background:#1F8C95;
    transform:translateY(-1px);
}
/* CSV hover → greyish */
.btn.secondary:hover{
    background:#e5e7eb;   /* soft grey */
}

/* PDF hover → darker */
.btn.primary:hover{
    background:#166d75;   /* darker shade of your teal */
    transform:translateY(-1px);
}

/* ================= FILTER ================= */

.ra-filter{
    display:flex;
    align-items:center;
    gap:16px;
    background:white;
    padding:18px;
    border-radius:14px;
    box-shadow:0 12px 30px rgba(0,0,0,.05);
    margin-bottom:30px;
}

.filter.search{
    flex:1;
    display:flex;
    align-items:center;
    gap:10px;
    background:#f1f5ff;
    padding:10px 14px;
    border-radius:10px;
}

.filter.search input{
    border:none;
    background:transparent;
    width:100%;
    outline:none;
}

.ra-filter select{
    border:none;
    background:#f1f5ff;
    padding:10px 14px;
    border-radius:10px;
}


/* ================= CHART SECTION ================= */

.ra-charts{
    margin-top:60px; /* increased space above charts */
}

/* two charts row */

.ra-chart-row{
    display:grid;
    grid-template-columns:1fr 1fr;
    gap:30px;
    margin-bottom:30px;
}

/* chart card */

.ra-chart-card{
    background:white;
    border-radius:18px;
    padding:26px 22px 22px 22px; /* extra top padding */
    box-shadow:0 18px 40px rgba(0,0,0,.06);
    transition:all .25s ease;
    display:flex;
    flex-direction:column;
    position:relative;
}

/* hover animation */

.ra-chart-card:hover{
    transform:translateY(-4px);
    box-shadow:
        0 22px 50px rgba(0,0,0,.12),
        0 8px 20px rgba(37,99,235,.08);
}

/* chart title */

.chart-title{
    font-weight:600;
    margin-bottom:14px;
    color:#334155;
}

/* chart canvas */

.ra-chart-card canvas{
    width:100%!important;
    height:320px!important;
}

/* bar chart extra space */

#tablesBarChart{
    height:380px !important;
    margin-top:10px;
}
/* ================= FIX PIE CHART STRETCH ================= */

#instanceDistributionChart {

max-height: 320px !important;

aspect-ratio: 1 / 1;

margin: 0 auto;

}
/* ================= BOTTOM SECTION ================= */
.pagination-bar{

display:flex;
justify-content:center;   /* centers horizontally */
align-items:center;

gap:14px;
margin-top:18px;

}

.page-btn{

background:#1F8C95;
color:white;
border:none;
padding:6px 14px;
border-radius:8px;
cursor:pointer;
font-size:13px;

}

.page-btn:disabled{

background:#cbd5e1;
cursor:not-allowed;

}

.page-info{

font-size:14px;
color:#475569;
font-weight:500;

}
.ra-bottom{
    display:grid;
    grid-template-columns:320px 1fr;
    gap:22px;
    margin-top:30px;
}

.section-title{
    font-weight:700;
    margin-bottom:16px;
}

/* ================= ACTIVITY ================= */

.ra-activity{
    background:white;
    padding:18px;
    border-radius:18px;
    box-shadow:0 18px 40px rgba(0,0,0,.05);
}

.activity-item{
    display:flex;
    justify-content:space-between;
    padding:14px;
    border-radius:10px;
    background:#f8faff;
    margin-bottom:10px;
}

.activity-item:hover{
    background:#eef4ff;
}

/* ================= TABLE ================= */

.ra-table{
    background:white;
    padding:20px;
    border-radius:18px;
    box-shadow:0 18px 40px rgba(0,0,0,.05);
}

.ra-table table{
    width:100%;
    border-collapse:collapse;
}

.ra-table th{
    font-size:13px;
    color:#64748b;
    padding:12px;
    border-bottom:1px solid #e2e8f0;
}

.ra-table td{
    padding:14px;
    border-bottom:1px solid #f1f5f9;
}

.ra-table tbody tr:hover{
    background:#f8faff;
}
.ra-table-performance{
background:white;
padding:26px;
border-radius:18px;
box-shadow:0 18px 40px rgba(0,0,0,.05);
margin-top:30px;
}

.performance-table{
width:100%;
border-collapse:collapse;
}

.performance-table th{
font-size:13px;
color:#64748b;
text-align:left;
padding:14px 8px;
border-bottom:1px solid #e5e7eb;
}

.performance-table td{
padding:18px 8px;
border-bottom:1px solid #f1f5f9;
font-size:16px;
color:#0f172a;
}

.table-name{
font-weight:600;
}

.runs-pill{
background:#e0ecff;
color:#2563eb;
padding:4px 12px;
border-radius:10px;
font-size:13px;
font-weight:500;
}

.performance-pill{
padding:6px 14px;
border-radius:20px;
font-size:13px;
font-weight:600;
display:inline-block;
}

.performance-pill.excellent{
background:#d1fae5;
color:#065f46;
}

.performance-pill.good{
background:#fef3c7;
color:#92400e;
}

.performance-pill.slow{
background:#fee2e2;
color:#991b1b;
}
/* ================= STATUS BADGES ================= */

.pill{
    padding:5px 10px;
    border-radius:999px;
    font-size:12px;
    font-weight:600;
}

.pill.success{
    background:#e6efff;
    color:#2563eb;
}

.pill.partial{
    background:#fff4e5;
    color:#f59e0b;
}

.pill.failed{
    background:#ffecec;
    color:#ef4444;
}
/* ================= KPI CARDS (FINAL MATCH DESIGN) ================= */
.ra-cards{
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 22px;
}

.ra-card{
  position: relative;
  background: white;
  border-radius: 18px;
  padding: 16px;
  box-shadow: 0 20px 45px rgba(0,0,0,.06);
  transition: all .35s ease;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  justify-content: space-between;
}

/* TOP BORDER EFFECT */

.ra-card::before{
  content:"";
  position:absolute;
  top:0;
  left:0;
  width:0%;
  height:4px;
  background:#1f8c95;
  border-radius:18px 18px 0 0;
  transition:width .35s ease;
}

/* HOVER GRADIENT */

.ra-card::after{
  content:"";
  position:absolute;
  inset:0;
  background:linear-gradient(
    135deg,
    rgba(37,99,235,0.12),
    rgba(255,255,255,0.05)
  );
  opacity:0;
  transition:opacity .35s ease;
}

/* CARD TOP */

.card-top{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:5px;
}

/* TITLE */

.card-title{
  font-size:15px;
  font-weight:600;
  color:#64748b;
}

/* VALUE */

.ra-card h2{
  font-size:34px;
  font-weight:700;
  color:#0f172a;
  margin-top:5px;
}

/* HOVER */

.ra-card:hover{
  transform:translateY(-6px);
  box-shadow:0 28px 60px rgba(0,0,0,.12);
}

.ra-card:hover::before{
  width:100%;
}

.ra-card:hover::after{
  opacity:1;
}

/* TREND TEXT */

.trend{
  font-size:14px;
  font-weight:600;
  display:flex;
  align-items:center;
  gap:6px;
}

/* TREND COLORS */

.trend.up{
  color:#16a34a;
}

.trend.down{
  color:#16a34a;
}

.trend.neutral{
  color:#7c3aed;
}

/* ICON BASE */

.card-icon{
  width:54px;
  height:54px;
  border-radius:14px;
  display:flex;
  align-items:center;
  justify-content:center;
  color:white;
  font-size:20px;
}

/* ================= CARD BACKGROUNDS ================= */

/* TOTAL RUNS */

.ra-card.runs{
  background:linear-gradient(135deg,#eef4ff,#dbeafe);
}

.ra-card.runs .card-icon{
  background:#3b82f6;
}

/* SUCCESS RATE */

.ra-card.success-rate{
  background:linear-gradient(135deg,#ecfdf5,#d1fae5);
}

.ra-card.success-rate .card-icon{
  background:#10b981;
}

/* RECORDS MIGRATED */

.ra-card.migrated{
  background:linear-gradient(135deg,#f5f3ff,#ede9fe);
}

.ra-card.migrated .card-icon{
  background:#8b5cf6;
}

/* AVG DURATION */

.ra-card.duration{
  background:linear-gradient(135deg,#fff7ed,#ffedd5);
}

.ra-card.duration .card-icon{
  background:#f59e0b;
}
/* ================= CUSTOM DROPDOWN STYLE ================= */

.custom-select {

appearance:none;

background:transparent;

border:none;

font-size:15px;

font-weight:600;

color:#111827;

cursor:pointer;

padding-right:22px;

}


/* custom dropdown arrow */

.filter-pill {

position:relative;

}


.filter-pill::after {

content:"⌄";

position:absolute;

right:14px;

font-size:14px;

color:#6b7280;

pointer-events:none;

}


/* dropdown popup styling */

select.custom-select option {

background:#f3f4f6;

padding:10px;

font-weight:500;

}


/* selected item */

select.custom-select option:checked {

background:#e5e7eb;

font-weight:600;

}

/* ================= MODERN CLEAN FILTER BAR ================= */

.ra-filter {

display: flex;

align-items: center;

gap: 20px;

background: #f8fafc; /* lighter, cleaner */

padding: 20px 26px;

border-radius: 18px;

box-shadow: 
0 6px 20px rgba(0,0,0,0.06);

margin-bottom: 30px;

flex-wrap: wrap;

}


/* ================= LABEL ================= */

.filter-label {

display: flex;

align-items: center;

