color: #334155;

}

.filter-label i {

color: #1F8C95;

font-size: 16px;

}


/* ================= FILTER PILLS ================= */

.filter-pill {

display: flex;

align-items: center;

gap: 10px;

background: #ffffff; /* FIX: was grey → now white */

padding: 10px 18px;

border-radius: 12px;

min-width: 170px;

border: 1px solid #e5e7eb;

transition: all 0.2s ease;

