}


/* ================= ICON ================= */

.filter-pill i {

color: #64748b;

font-size: 14px;

}


/* ================= SELECT ================= */

.custom-select {

appearance: none;

border: none;

background: transparent;

font-size: 14px;

font-weight: 600;

color: #111827;

cursor: pointer;

