right: 12px;

top: 50%;

transform: translateY(-50%);

font-size: 13px;

color: #6b7280;

pointer-events: none;

}


/* ================= DROPDOWN OPTIONS ================= */

select.custom-select option {

background: #ffffff;

padding: 10px;

