}

sp_widget.script:
(function () {

  data.side = $sp.getWidget('dmm_sidebar');

  data.runs = [];
  data.activity = [];

  /* ================= KPI COUNTERS ================= */

  var totalRuns = 0;
  var successRuns = 0;
  var partialRuns = 0;
  var failedRuns = 0;
  var totalRecords = 0;
  var totalDuration = 0;
  var instanceName = '';

  /* ================= LOAD MIGRATION DETAILS ================= */

  var gr = new GlideRecord('x_sysus_data_mig_0_migration_details');

  gr.addQuery('sys_created_by', gs.getUserName());
  gr.orderByDesc('sys_created_on');
  gr.query();

  gs.info('=== DEBUG USER: ' + gs.getUserName() + ', Found: ' + gr.getRowCount() + ' records ===');

  while (gr.next()) {

    totalRuns++;

    var inserted = parseInt(gr.getValue('records_inserted') || 0);
    var updated  = parseInt(gr.getValue('records_updated')  || 0);
    var failed   = parseInt(gr.getValue('records_failed')   || 0);
    var fetched  = parseInt(gr.getValue('records_fetched')  || 0);
    var records  = inserted + updated;

    totalRecords += records;

    /* ================= DETERMINE STATUS ================= */

    var successRate = parseInt(gr.getValue('success_rate') || 0);
    var status = 'success';

    if (successRate === 0) {
      status = 'failed';
      failedRuns++;
    } else if (successRate === 100) {
      status = 'success';
      successRuns++;
    } else {
      status = 'partial';
      partialRuns++;
    }

    /* ================= TABLE LIST ================= */

    var tables = [];
    try {
      var tableJSON = JSON.parse(gr.getValue('table') || '{}');
      for (var key in tableJSON) {
        tables.push(key);
      }
      if (tables.length === 0) {
        tables = ['Unknown Table'];
      }
    } catch (e) {
      tables = ['Parse Error'];
    }

    /* ================= DURATION ================= */

    var duration = gr.getValue('duration') || '0 min 0 sec';

    totalDuration += 0;

    /* ================= CONNECTION LOOKUP ================= */

    var connectionSysId = gr.getValue('connection');
    var connectionName  = '';

    if (connectionSysId) {
      var connLookup = new GlideRecord('x_sysus_data_mig_0_connection');
      if (connLookup.get(connectionSysId)) {
        instanceName   = connLookup.getValue('name');
        connectionName = connLookup.getValue('name');
      }
    }

    /* ================= FIX: push created_raw (ISO) for reliable client-side date parsing ================= */

    data.runs.push({
      run_id:        gr.getValue('number'),
      number:        gr.getValue('number'),
      instance:      (gr.getValue('instance_url') || '').trim().replace(/\/$/, '').toLowerCase(),
      instance_name: instanceName,
      created:       gr.getDisplayValue('sys_created_on'),
      created_raw:   gr.getValue('sys_created_on'),        // ISO value — client uses this for date filters
      tables:        tables,
      records:       records,
      status:        status,
      duration:      duration,
      success_rate:  gr.getValue('success_rate')
    });

    data.activity.push({
      created: gr.getDisplayValue('sys_created_on'),
      tables:  tables,
      records: records,
      status:  status
    });
  }

  /* ================= CONNECTIONS ================= */

  data.connections = [];

  var connGR = new GlideRecord('x_sysus_data_mig_0_connection');
  connGR.addQuery('sys_created_by', gs.getUserName());
  connGR.query();

  while (connGR.next()) {
    data.connections.push({
      /* FIX: normalize url here so instance filter matching is consistent */
      url:  (connGR.getValue('url') || '').trim().replace(/\/$/, '').toLowerCase(),
      name: connGR.getDisplayValue('name')
    });
  }

  /* ================= KPI SUMMARY ================= */

  data.stats = {
    total:        totalRuns,
    success:      successRuns,
    failed:       failedRuns,
    records:      totalRecords,
    avg_duration: (totalRuns ? Math.round(totalDuration / totalRuns) : 0)
  };

  gs.info('=== FINAL: ' + totalRuns + ' runs for user ' + gs.getUserName() + ' ===');

})();
